Here's a complete example with both `[DataRow]` and `[DynamicData]` approaches:

```csharp
// PriceCalculator.cs
public class PriceCalculator
{
    public decimal CalculateTotal(decimal unitPrice, int quantity)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(unitPrice);
        ArgumentOutOfRangeException.ThrowIfNegativeOrZero(quantity);
        return unitPrice * quantity;
    }

    public decimal ApplyDiscount(decimal total, decimal discountPercent)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(total);
        if (discountPercent is < 0 or > 100)
            throw new ArgumentOutOfRangeException(nameof(discountPercent));
        return total * (1 - discountPercent / 100m);
    }
}
```

```csharp
// PriceCalculatorTests.cs
using System.Reflection;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── DataRow: best for simple inline cases ──

    [TestMethod]
    [DataRow(10.00, 1,  10.00,  DisplayName = "Single item")]
    [DataRow(10.00, 5,  50.00,  DisplayName = "Multiple items")]
    [DataRow(0.01,  1,   0.01,  DisplayName = "Minimum price")]
    [DataRow(99.99, 100, 9999.00, DisplayName = "Large quantity")]
    public void CalculateTotal_ReturnsExpected(
        double unitPrice, int quantity, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(0,    1, DisplayName = "Zero price throws")]
    [DataRow(10.0, 0, DisplayName = "Zero quantity throws")]
    public void CalculateTotal_InvalidInputs_Throws(
        double unitPrice, int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity));
    }

    // ── DynamicData: best for complex types or computed cases ──

    [TestMethod]
    [DynamicData(nameof(DiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_ReturnsExpected(
        decimal total, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(total, discountPercent);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> DiscountCases()
    {
        yield return [100m,  0m,   100m];    // no discount
        yield return [100m, 10m,    90m];    // 10% off
        yield return [100m, 50m,    50m];    // half off
        yield return [100m, 100m,    0m];    // free
        yield return [249.99m, 15m, 212.4915m]; // fractional
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Property)]
    public void ApplyDiscount_InvalidInputs_Throws(
        decimal total, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(total, discountPercent));
    }

    public static IEnumerable<object[]> InvalidDiscountCases => new[]
    {
        new object[] { -1m,  10m },   // negative total
        new object[] { 100m, -1m },   // negative discount
        new object[] { 100m, 101m },  // discount > 100%
    };
}
```

**Key points:**

- **`[DataRow]`** — use for simple primitives (note: `decimal` literals aren't compile-time constants, so pass `double` and cast)
- **`[DynamicData]`** — use when you need `decimal` precision, complex objects, or computed test data; works with both methods (`DynamicDataSourceType.Method`) and properties (`Property`)
- **`DisplayName`** on `DataRow` makes test explorer output readable
- Separate test methods for happy-path vs. error cases keeps intent clear
